import type { AIProvider } from '@/lib/agent/types'
import { prisma } from '@/lib/db/prisma'

const TOKEN_RATES: Record<string, number> = {
  'gpt-4o': 0.000005,
  'gpt-4o-mini': 0.0000015,
  'claude-sonnet-4-20250514': 0.000005,
  'claude-3-5-haiku-20241022': 0.000001,
  'grok-3': 0.000005,
  'grok-3-latest': 0.000005,
  'gemini-2.0-flash': 0.00000035,
  'gemini-2.5-flash-preview-05-20': 0.00000035,
  'gemini-1.5-pro': 0.0000035,
}

export interface TokenUsage {
  promptTokens?: number
  completionTokens?: number
  totalTokens?: number
}

interface LogUsageParams {
  provider?: AIProvider | string
  model: string
  purpose: string
  promptTokens?: number
  completionTokens?: number
  totalTokens?: number
  estimatedCostUsd?: number
  relatedContentId?: string
  relatedAgentRunId?: string
}

export async function logApiUsage(params: LogUsageParams) {
  try {
    await prisma.apiUsageLog.create({
      data: {
        provider: params.provider ?? 'xai',
        model: params.model,
        purpose: params.purpose,
        promptTokens: params.promptTokens,
        completionTokens: params.completionTokens,
        totalTokens: params.totalTokens,
        estimatedCostUsd: params.estimatedCostUsd,
        relatedContentId: params.relatedContentId,
        relatedAgentRunId: params.relatedAgentRunId,
      },
    })
  } catch (e) {
    console.error('Failed to log API usage:', e)
  }
}

export function estimateCost(model: string, totalTokens: number): number {
  const rate = TOKEN_RATES[model] ?? 0.000005
  return totalTokens * rate
}

export function formatCost(usd: number): string {
  if (usd < 0.01) return `$${usd.toFixed(4)}`
  return `$${usd.toFixed(2)}`
}

const PURPOSE_LABELS: Record<string, string> = {
  generate_episode: 'Content generation',
  regenerate_episode: 'Platform regenerate',
  test_connection: 'Connection test',
  brand_analysis: 'Website analysis',
  planning_cycle: 'Planning cycle',
  regenerate: 'Content regenerate',
  recommend_topics: 'Topic suggestions',
}

export function formatUsagePurpose(purpose: string): string {
  if (PURPOSE_LABELS[purpose]) return PURPOSE_LABELS[purpose]
  if (purpose.startsWith('image:')) return purpose.replace(/^image:\s*/, 'Image · ')
  return purpose.replace(/_/g, ' ')
}

import { callAI } from '@/lib/ai/call-ai'

interface XAIChatMessage {
  role: 'system' | 'user' | 'assistant'
  content: string
}

interface CallXAIParams {
  messages: XAIChatMessage[]
  model?: string
  temperature?: number
  purpose: string
  relatedContentId?: string
  relatedAgentRunId?: string
}

/** Backward-compatible xAI wrapper — delegates to unified callAI */
export async function callXAI(params: CallXAIParams) {
  const result = await callAI({
    provider: 'xai',
    messages: params.messages,
    model: params.model,
    temperature: params.temperature,
    purpose: params.purpose,
    jsonMode: true,
    relatedContentId: params.relatedContentId,
    relatedAgentRunId: params.relatedAgentRunId,
  })

  return {
    choices: [{ message: { content: result.content } }],
    usage: {
      prompt_tokens: result.usage.promptTokens,
      completion_tokens: result.usage.completionTokens,
      total_tokens: result.usage.totalTokens,
    },
  }
}

import type { AIProvider } from "@/lib/agent/types";

export interface AIProviderConfig {
  id: AIProvider;
  label: string;
  description: string;
  defaultModel: string;
  models: string[];
  keyPlaceholder: string;
  keyUrl: string;
}

export const AI_PROVIDERS: AIProviderConfig[] = [
  { id: "openai", label: "OpenAI", description: "GPT-4o and other OpenAI models", defaultModel: "gpt-4o", models: ["gpt-4o", "gpt-4o-mini"], keyPlaceholder: "sk-...", keyUrl: "https://platform.openai.com/api-keys" },
  { id: "anthropic", label: "Anthropic", description: "Claude Sonnet and other Anthropic models", defaultModel: "claude-sonnet-4-20250514", models: ["claude-sonnet-4-20250514", "claude-3-5-haiku-20241022"], keyPlaceholder: "sk-ant-...", keyUrl: "https://console.anthropic.com/settings/keys" },
  { id: "xai", label: "xAI (Grok)", description: "Grok models via xAI API", defaultModel: "grok-3", models: ["grok-3", "grok-3-latest"], keyPlaceholder: "xai-...", keyUrl: "https://console.x.ai/" },
  { id: "google", label: "Google (Gemini)", description: "Gemini models via Google AI Studio", defaultModel: "gemini-2.0-flash", models: ["gemini-2.0-flash", "gemini-2.5-flash-preview-05-20", "gemini-1.5-pro"], keyPlaceholder: "AIza...", keyUrl: "https://aistudio.google.com/apikey" },
];

export const AI_PROVIDER_MAP = Object.fromEntries(AI_PROVIDERS.map((p) => [p.id, p])) as Record<AIProvider, AIProviderConfig>;

export function getDefaultModel(provider: AIProvider): string {
  return AI_PROVIDER_MAP[provider].defaultModel;
}

import type { AIProvider } from "@/lib/agent/types";
import { getApiKey } from "@/lib/settings/api-key";

export type ImageAspectRatio = "square" | "landscape" | "portrait";

export interface ImageProviderConfig { provider: AIProvider; model: string; label: string; }

export const IMAGE_CAPABLE_PROVIDERS: AIProvider[] = ["openai", "google", "xai"];

export const IMAGE_PROVIDER_CONFIG = {
  openai: { provider: "openai", model: "dall-e-3", label: "DALL·E 3" },
  google: { provider: "google", model: "gemini-2.0-flash-preview-image-generation", label: "Gemini Image" },
  xai: { provider: "xai", model: "grok-imagine-image-quality", label: "Grok Imagine" },
} as const;

export const DALLE3_SIZES = { square: "1024x1024", landscape: "1792x1024", portrait: "1024x1792" } as const;
export const GROK_ASPECT_RATIOS = { square: "1:1", landscape: "16:9", portrait: "9:16" } as const;
export const IMAGE_COST_ESTIMATES = { "dall-e-3": 0.04, "gemini-2.0-flash-preview-image-generation": 0.03, "grok-imagine-image-quality": 0.05, "grok-imagine-image": 0.02 };

export function getImageProviderLabel(provider: AIProvider): string | null {
  if (!supportsImageGeneration(provider)) return null;
  return IMAGE_PROVIDER_CONFIG[provider as keyof typeof IMAGE_PROVIDER_CONFIG].label;
}

export function supportsImageGeneration(provider: AIProvider): boolean {
  return IMAGE_CAPABLE_PROVIDERS.includes(provider);
}

type ImageProvider = Extract<AIProvider, "openai" | "google" | "xai">;

export async function resolveImageProvider(preferred: AIProvider): Promise<ImageProvider | null> {
  const candidates: AIProvider[] = [preferred, "xai", "openai", "google"];
  const seen = new Set<AIProvider>();
  for (const provider of candidates) {
    if (seen.has(provider) || !supportsImageGeneration(provider)) continue;
    seen.add(provider);
    const apiKey = await getApiKey(provider);
    if (apiKey) return provider as ImageProvider;
  }
  return null;
}

import type { SocialPlatform } from "@/lib/agent/types";

