  { id: "youtube_short", label: "YouTube Shorts", shortLabel: "YT Shorts", description: "60–90s faceless script, scene prompts, thumbnail, upload package", category: "video", defaultSelected: true },
  { id: "youtube_long", label: "YouTube Long-form", shortLabel: "YT Long", description: "Outline, full script, B-roll prompts, thumbnail, SEO metadata", category: "video", defaultSelected: false },
  { id: "tiktok", label: "TikTok", shortLabel: "TikTok", description: "Short script, on-screen text, scene prompts, hashtags", category: "video", defaultSelected: false },
  { id: "instagram", label: "Instagram", shortLabel: "IG", description: "Reel script, carousel prompts, caption, hashtags", category: "social", defaultSelected: false },
  { id: "x", label: "X (Twitter)", shortLabel: "X", description: "Post or thread with hook, body, hashtags, media prompt", category: "social", defaultSelected: false, charLimit: 280 },
  { id: "linkedin", label: "LinkedIn", shortLabel: "LinkedIn", description: "Professional post or thread with hook and CTA", category: "social", defaultSelected: false, charLimit: 3000 },
  { id: "facebook", label: "Facebook", shortLabel: "Facebook", description: "Engaging post with hook, body, and image prompt", category: "social", defaultSelected: false, charLimit: 63206 },
];

export const PLATFORM_MAP = Object.fromEntries(PLATFORMS.map((p) => [p.id, p])) as Record<SocialPlatform, PlatformConfig>;
export const DEFAULT_PLATFORMS: SocialPlatform[] = PLATFORMS.filter((p) => p.defaultSelected).map((p) => p.id);
export const VIDEO_PLATFORMS = PLATFORMS.filter((p) => p.category === "video");
export const SOCIAL_PLATFORMS = PLATFORMS.filter((p) => p.category === "social");

export function getPlatformLabel(id: SocialPlatform): string { return PLATFORM_MAP[id]?.label ?? id; }

export function getEpisodePlatformIds(content: Partial<Record<SocialPlatform, unknown>>): SocialPlatform[] {
  return (Object.keys(content) as SocialPlatform[]).filter((key) => content[key] != null);
}

import { describe, expect, it } from 'vitest'
import { formatFullPackage, formatPlatformForCopy, getPlatformCopyLabel } from '@/lib/content/format-package'
import type { ContentEpisodePayload } from '@/lib/agent/types'

const samplePayload: ContentEpisodePayload = {
  platforms: ['linkedin', 'x'],
  strategyNote: 'Focus on thought leadership around AI agents in production.',
  agentReasoning: 'LinkedIn resonates with this audience; X for a punchy hook.',
  content: {
    linkedin: { format: 'POST', hook: 'Most AI agents fail in production.', body: 'Here is why — and what actually works.', hashtags: ['AI', 'Marketing'], cta: 'Follow for more.' },
    x: { format: 'POST', hook: 'Hot take:', body: 'Your AI agent is not broken. Your approval workflow is.', hashtags: ['AI'] },
  },
}

describe('formatPlatformForCopy', () => {
  it('formats LinkedIn post with hashtags', () => {
    const text = formatPlatformForCopy('linkedin', samplePayload.content)
    expect(text).toContain('Most AI agents fail in production.')
    expect(text).toContain('#AI')
  })
})

describe('formatFullPackage', () => {
  it('includes topic, strategy, and platform sections', () => {
    const full = formatFullPackage('AI agents in prod', samplePayload)
    expect(full).toContain('Topic: AI agents in prod')
    expect(full).toContain('## Strategy')
  })
})

describe('getPlatformCopyLabel', () => {
  it('returns human labels', () => {
    expect(getPlatformCopyLabel('linkedin')).toBe('Copy LinkedIn post')
  })
})

import type { ContentEpisodePayload, PlatformContent, SocialPlatform, SocialPostContent } from '@/lib/agent/types'
import { getPlatformLabel } from '@/lib/constants/platforms'

function socialPostText(data: SocialPostContent): string {
  if (data.format === 'THREAD') return data.body
  const parts = [data.hook, data.body]
  if (data.cta) parts.push(data.cta)
  const hashtags = data.hashtags?.length ? '\n\n' + data.hashtags.map((h) => (h.startsWith('#') ? h : `#${h}`)).join(' ') : ''
  return parts.filter(Boolean).join('\n\n') + hashtags
}

export function formatPlatformForCopy(platform: SocialPlatform, content: PlatformContent): string {
  switch (platform) {
    case 'x': case 'linkedin': case 'facebook': { const data = content[platform]; if (!data) return ''; return socialPostText(data) }
    case 'instagram': { const data = content.instagram; if (!data) return ''; const hashtags = data.hashtags.map((h) => (h.startsWith('#') ? h : `#${h}`)).join(' '); return `${data.hook}\n\n${data.caption}\n\n${hashtags}` }
    case 'tiktok': { const data = content.tiktok; if (!data) return ''; const script = `${data.script.hook}\n\n${data.script.body}\n\n${data.script.cta}`; const tags = data.hashtags.map((h) => (h.startsWith('#') ? h : `#${h}`)).join(' '); return `CAPTION:\n${data.caption}\n\n---\nSCRIPT (voiceover):\n${script}\n\n---\nHASHTAGS:\n${tags}` }
    case 'youtube_short': { const data = content.youtube_short; if (!data) return ''; const script = `${data.script.hook}\n\n${data.script.body}\n\n${data.script.cta}`; const titles = data.youtube.titleOptions.map((t, i) => `${i + 1}. ${t}`).join('\n'); return ['TITLE OPTIONS:', titles, '', 'DESCRIPTION:', data.youtube.description, '', 'TAGS:', data.youtube.tags.join(', '), '', 'SCRIPT:', script].join('\n') }
    case 'youtube_long': { const data = content.youtube_long; if (!data) return ''; const titles = data.youtube.titleOptions.map((t, i) => `${i + 1}. ${t}`).join('\n'); return ['TITLE OPTIONS:', titles, '', 'DESCRIPTION:', data.youtube.description, '', 'TAGS:', data.youtube.tags.join(', '), '', 'SCRIPT:', data.script].join('\n') }
    default: return ''
  }
}

export function formatFullPackage(topic: string, payload: ContentEpisodePayload): string {
  const sections = [`# Content Package`, `Topic: ${topic}`, '', `## Strategy`, payload.strategyNote, '', `---`, '']
  for (const platform of payload.platforms) {
    const text = formatPlatformForCopy(platform, payload.content)
    if (!text) continue
    sections.push(`## ${getPlatformLabel(platform)}`, text, '', '---', '')
  }
  return sections.join('\n').trim()
}

export function getPlatformCopyLabel(platform: SocialPlatform): string {
  const labels: Record<SocialPlatform, string> = { x: 'Copy X post', linkedin: 'Copy LinkedIn post', facebook: 'Copy Facebook post', instagram: 'Copy Instagram caption', tiktok: 'Copy TikTok package', youtube_short: 'Copy YouTube Shorts package', youtube_long: 'Copy YouTube video package' }
  return labels[platform]
}

import { PrismaClient } from '@prisma/client'

const prismaClientSingleton = () => {
  return new PrismaClient({ log: process.env.NODE_ENV === 'development' ? ['error', 'warn'] : ['error'] })
}

declare const globalThis: { prismaGlobal: ReturnType<typeof prismaClientSingleton> } & typeof global

const prisma = globalThis.prismaGlobal ?? prismaClientSingleton()

export { prisma }

if (process.env.NODE_ENV !== 'production') globalThis.prismaGlobal = prisma
